private getProvider(tier: ModelTier): LlmProvider {
    switch (tier) {
      case 'local':
        return this.providers.local ?? this.providers.lightweight
      case 'lightweight':
        return this.providers.lightweight
      case 'standard':
        return this.providers.standard
    }
  }

